using namespace std;
int A, B, C, D, E, F, G, H, I, J, K, L, N, M, O, P, Q, R, S, T;
int d[0x200], st[0x200], cnt[0x200];
vector<pair<int, int>> g[0x200];
int spfa()
{
	memset(d, -0x3f, sizeof d);
	queue<int> q;
	q.push(S);
	d[S] = D;
	while (q.size())
	{
		int top = q.front();
		st[top] = 0;
		q.pop();
		for (auto s : g[top])
		{
			if (d[s.first] < d[top] + s.second)
			{
				d[s.first] = d[top] + s.second;
				++cnt[s.first];
				if (cnt[s.first] > P + 1)return -1;
				if (st[s.first])continue;
				st[s.first] = 1;
				q.push(s.first);

			}
		}
	}int ans=LLONG_MIN;
	for(int i=1;i<=C;++i)
	{

		ans=max(d[i],ans);
	}
	return ans;

}

